<template>
  <div style="color: white; display: flex;">
    <span style="display: flex; flex-direction: column;">
      <span v-for="(item, idx) in itemsByFirstHalf" :key="idx">
        <fa-icon class="item-icon" icon="caret-right"/> {{ item }}
      </span>
    </span>

    <span
      v-if="itemsBySecondHalf.length > 0"
      class="ml-4"
      style="display: flex; flex-direction: column;">
      <span v-for="(item, idx) in itemsBySecondHalf" :key="idx">
        <fa-icon class="item-icon" icon="caret-right"/> {{ item }}
      </span>
    </span>
  </div>
</template>

<script>
export default {
  name: 'ItemList',

  props: {
    items: {
      type: Array,
      required: true,
    },
    isTwoColumns: {
      type: Boolean,
      default: false,
    },
  },

  computed: {
    itemsQuotient: function () {
      return Math.floor(this.items.length / 2);
    },

    itemsByFirstHalf: function () {
      if (!this.isTwoColumns) {
        return this.items;
      }

      const remainder = this.items.length % 2;
      const total = this.itemsQuotient + remainder;

      return this.items.slice(0, total);
    },

    itemsBySecondHalf: function () {
      if (!this.isTwoColumns) {
        return [];
      }

      return this.items.slice(this.itemsQuotient);
    },
  },
};
</script>

<style scoped>
.item-icon {
  margin-right: 0.5rem;
}
</style>
